// 解析 webhook 数据
const body = $input.first().json.body;

// 从 Gitea webhook 中提取信息
const result = {
  project: body.repository?.name || 'unknown',
  branch: body.ref?.replace('refs/heads/', '') || 'unknown',
  commit: body.after?.substring(0, 7) || 'unknown',
  pusher: body.pusher?.username || 'unknown',
  timestamp: new Date().toISOString()
};

console.log('CI Failure detected:', result);
return [{ json: result }];
